  5â†’package kotlinx.coroutines.future
  6â†’
  7â†’import kotlinx.coroutines.*
  8â†’import kotlinx.coroutines.CancellationException
  9â†’import java.util.concurrent.*
 10â†’import java.util.function.*
 11â†’import kotlin.coroutines.*
 12â†’
 13â†’/**
 14â†’ * Starts a new coroutine and returns its result as an implementation of [CompletableFuture].
 15â†’ * The running coroutine is cancelled when the resulting future is cancelled or otherwise completed.
 16â†’ *
 17â†’ * The coroutine context is inherited from a [CoroutineScope], additional context elements can be specified with the [context] argument.
 18â†’ * If the context does not have any dispatcher nor any other [ContinuationInterceptor], then [Dispatchers.Default] is used.
 19â†’ * The parent job is inherited from a [CoroutineScope] as well, but it can also be overridden
 20â†’ * with corresponding [context] element.
 21â†’ *
 22â†’ * By default, the coroutine is immediately scheduled for execution.
 23â†’ * Other options can be specified via `start` parameter. See [CoroutineStart] for details.
 24â†’ * A value of [CoroutineStart.LAZY] is not supported
 25â†’ * (since `CompletableFuture` framework does not provide the corresponding capability) and
 26â†’ * produces [IllegalArgumentException].
 27â†’ *
 28â†’ * See [newCoroutineContext][CoroutineScope.newCoroutineContext] for a description of debugging facilities that are available for newly created coroutine.
 29â†’ *
 30â†’ * @param context additional to [CoroutineScope.coroutineContext] context of the coroutine.
 31â†’ * @param start coroutine start option. The default value is [CoroutineStart.DEFAULT].
 32â†’ * @param block the coroutine code.
 33â†’ */
 34â†’public fun <T> CoroutineScope.future(
 35â†’    context: CoroutineContext = EmptyCoroutineContext,
 36â†’    start: CoroutineStart = CoroutineStart.DEFAULT,
 37â†’    block: suspend CoroutineScope.() -> T
 38â†’) : CompletableFuture<T> {
 39â†’    require(!start.isLazy) { "$start start is not supported" }
 40â†’    val newContext = this.newCoroutineContext(context)
 41â†’    val future = CompletableFuture<T>()
 42â†’    val coroutine = CompletableFutureCoroutine(newContext, future)
 43â†’    future.handle(coroutine) // Cancel coroutine if future was completed externally
 44â†’    coroutine.start(start, coroutine, block)
 45â†’    return future
 46â†’}
 47â†’
 48â†’private class CompletableFutureCoroutine<T>(
 49â†’    context: CoroutineContext,
 50â†’    private val future: CompletableFuture<T>
 51â†’) : AbstractCoroutine<T>(context, initParentJob = true, active = true), BiFunction<T?, Throwable?, Unit> {
 52â†’    override fun apply(value: T?, exception: Throwable?) {
 53â†’        cancel()
 54â†’    }
 55â†’
 56â†’    override fun onCompleted(value: T) {
 57â†’        future.complete(value)
 58â†’    }
 59â†’
 60â†’    override fun onCancelled(cause: Throwable, handled: Boolean) {
 61â†’        if (!future.completeExceptionally(cause) && !handled) {
 62â†’            // prevents loss of exception that was not handled by parent & could not be set to CompletableFuture
 63â†’            handleCoroutineException(context, cause)
 64â†’        }
 65â†’    }
 66â†’}
 67â†’
 68â†’/**
 69â†’ * Converts this deferred value to the instance of [CompletableFuture].
 70â†’ * The deferred value is cancelled when the resulting future is cancelled or otherwise completed.
 71â†’ */
 72â†’public fun <T> Deferred<T>.asCompletableFuture(): CompletableFuture<T> {
 73â†’    val future = CompletableFuture<T>()
 74â†’    setupCancellation(future)
 75â†’    invokeOnCompletion {
 76â†’        try {
 77â†’            future.complete(getCompleted())
 78â†’        } catch (t: Throwable) {
 79â†’            future.completeExceptionally(t)
 80â†’        }
 81â†’    }
 82â†’    return future
 83â†’}
 84â†’
 85â†’/**
 86â†’ * Converts this job to the instance of [CompletableFuture].
 87â†’ * The job is cancelled when the resulting future is cancelled or otherwise completed.
 88â†’ */
 89â†’public fun Job.asCompletableFuture(): CompletableFuture<Unit> {
 90â†’    val future = CompletableFuture<Unit>()
 91â†’    setupCancellation(future)
 92â†’    invokeOnCompletion { cause ->
 93â†’        if (cause === null) future.complete(Unit)
 94â†’        else future.completeExceptionally(cause)
 95â†’    }
 96â†’    return future
 97â†’}
 98â†’
 99â†’private fun Job.setupCancellation(future: CompletableFuture<*>) {
100â†’    future.handle { _, exception ->
101â†’        cancel(exception?.let {
102â†’            it as? CancellationException ?: CancellationException("CompletableFuture was completed exceptionally", it)
103â†’        })
104â†’    }
105â†’}
106â†’
107â†’/**
108â†’ * Converts this [CompletionStage] to an instance of [Deferred].
109â†’ *
110â†’ * The [CompletableFuture] that corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
111â†’ * is cancelled when the resulting deferred is cancelled.
112â†’ */
113â†’@Suppress("DeferredIsResult")
114â†’public fun <T> CompletionStage<T>.asDeferred(): Deferred<T> {
115â†’    val future = toCompletableFuture() // retrieve the future
116â†’    // Fast path if already completed
117â†’    if (future.isDone) {
118â†’        return try {
119â†’            @Suppress("UNCHECKED_CAST")
120â†’            CompletableDeferred(future.get() as T)
121â†’        } catch (e: Throwable) {
122â†’            // unwrap original cause from ExecutionException
123â†’            val original = (e as? ExecutionException)?.cause ?: e
124â†’            CompletableDeferred<T>().also { it.completeExceptionally(original) }
125â†’        }
126â†’    }
127â†’    val result = CompletableDeferred<T>()
128â†’    handle { value, exception ->
129â†’        try {
130â†’            if (exception == null) {
131â†’                // the future has completed normally
132â†’                result.complete(value)
133â†’            } else {
134â†’                // the future has completed with an exception, unwrap it consistently with fast path
135â†’                // Note: In the fast-path the implementation of CompletableFuture.get() does unwrapping
136â†’                result.completeExceptionally((exception as? CompletionException)?.cause ?: exception)
137â†’            }
138â†’        } catch (e: Throwable) {
139â†’            // We come here iff the internals of Deferred threw an exception during its completion
140â†’            handleCoroutineException(EmptyCoroutineContext, e)
141â†’        }
142â†’    }
143â†’    result.cancelFutureOnCompletion(future)
144â†’    return result
145â†’}
146â†’
147â†’/**
148â†’ * Awaits for completion of [CompletionStage] without blocking a thread.
149â†’ *
150â†’ * This suspending function is cancellable.
151â†’ * If the [Job] of the current coroutine is cancelled or completed while this suspending function is waiting, this function
152â†’ * stops waiting for the completion stage and immediately resumes with [CancellationException][kotlinx.coroutines.CancellationException].
153â†’ *
154â†’ * This method is intended to be used with one-shot futures, so on coroutine cancellation the [CompletableFuture] that
155â†’ * corresponds to this [CompletionStage] (see [CompletionStage.toCompletableFuture])
156â†’ * is cancelled. If cancelling the given stage is undesired, `stage.asDeferred().await()` should be used instead.
157â†’ */
158â†’public suspend fun <T> CompletionStage<T>.await(): T {
159â†’    val future = toCompletableFuture() // retrieve the future
160â†’    // fast path when CompletableFuture is already done (does not suspend)
161â†’    if (future.isDone) {
162â†’        try {
163â†’            @Suppress("UNCHECKED_CAST", "BlockingMethodInNonBlockingContext")
164â†’            return future.get() as T
165â†’        } catch (e: ExecutionException) {
166â†’            throw e.cause ?: e // unwrap original cause from ExecutionException
167â†’        }
168â†’    }
169â†’    // slow path -- suspend
170â†’    return suspendCancellableCoroutine { cont: CancellableContinuation<T> ->
171â†’        val consumer = ContinuationHandler(cont)
172â†’        handle(consumer)
173â†’        cont.invokeOnCancellation {
174â†’            future.cancel(false)
175â†’            consumer.cont = null // shall clear reference to continuation to aid GC
176â†’        }
177â†’    }
178â†’}
179â†’
180â†’private class ContinuationHandler<T>(
181â†’    @Volatile @JvmField var cont: Continuation<T>?
182â†’) : BiFunction<T?, Throwable?, Unit> {
183â†’    @Suppress("UNCHECKED_CAST")
184â†’    override fun apply(result: T?, exception: Throwable?) {
185â†’        val cont = this.cont ?: return // atomically read current value unless null
186â†’        if (exception == null) {
187â†’            // the future has completed normally
188â†’            cont.resume(result as T)
189â†’        } else {
190â†’            // the future has completed with an exception, unwrap it to provide consistent view of .await() result and to propagate only original exception
191â†’            cont.resumeWithException((exception as? CompletionException)?.cause ?: exception)
192â†’        }
193â†’    }
194â†’}
195â†’

