package kotlinx.coroutines.future

import kotlinx.coroutines.*
import org.junit.Test
import java.util.concurrent.CountDownLatch
import java.util.concurrent.TimeUnit
import kotlin.test.*

class FutureCancellationUnhandledExceptionTest : TestBase() {

    @Test
    fun testNoUnhandledExceptionAfterFutureCancellation() {
        val cancelled = CountDownLatch(1)
        val future = GlobalScope.future(start = CoroutineStart.UNDISPATCHED) {
            try {
                awaitCancellation()
            } finally {
                cancelled.countDown()
                throw TestException("boom")
            }
        }

        future.cancel(true)
        assertTrue(future.isCancelled)
        assertTrue(cancelled.await(10, TimeUnit.SECONDS))
        // Give the global exception handler a chance to process any unexpected unhandled exceptions.
        Thread.sleep(100)
    }
}
