466â†’        launch(start = CoroutineStart.UNDISPATCHED) {
467â†’            expect(5)
468â†’            // Slow path on await shall produce TestException, too
469â†’            assertFailsWith<TestException> { fSlow.await() } // will suspend here
470â†’            assertFailsWith<TestException> { dSlow.await() }
471â†’            finish(7)
472â†’        }
