479â†’        val cause = e.cause!!
480â†’        assertTrue(cause is T)
481â†’        for ((index, clazz) in suppressed.withIndex()) {
482â†’            assertTrue(clazz.isInstance(cause.suppressed[index]))
483â†’        }
484â†’    }
